import { useState } from "react";

function Join({ setRoom, setName, setRole }) {
  const [roomInput, setRoomInput] = useState("");
  const [nameInput, setNameInput] = useState("");

  return (
    <div>
      <h2>Join Quiz</h2>

      <input
        placeholder="Your name"
        onChange={(e) => setNameInput(e.target.value)}
      />

      <input
        placeholder="Room code"
        onChange={(e) => setRoomInput(e.target.value)}
      />

      <button
        onClick={() => {
          setRoom(roomInput);
          setName(nameInput);

          // ВРЕМЕННО ДЛЯ ТЕСТА
          if (nameInput === "admin") {
            setRole("organizer");
          } else {
            setRole("participant");
          }
        }}
      >
        Join
      </button>
    </div>
  );
}

export default Join;
